#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 32

__global__ void matmul_tiled(const float* A, const float* B, float* C, int M, int K, int N) {
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;
    int k = blockIdx.z;

    float acc = 0.0f;

    for (int m = 0; m < (M + TILE_SIZE - 1) / TILE_SIZE; ++m) {
        int a_row = m * TILE_SIZE + threadIdx.y;
        int b_col = m * TILE_SIZE + threadIdx.x;

        if (a_row < M && k < K) {
            As[threadIdx.y][threadIdx.x] = A[a_row * K + k];
        } else {
            As[threadIdx.y][threadIdx.x] = 0.0f;
        }

        if (k < K && b_col < N) {
            Bs[threadIdx.y][threadIdx.x] = B[k * N + b_col];
        } else {
            Bs[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        for (int i = 0; i < TILE_SIZE; ++i) {
            acc += As[threadIdx.y][i] * Bs[i][threadIdx.x];
        }

        __syncthreads();
    }

    if (row < M && col < N) {
        C[row * N + col] = acc;
    }
}

